10	const SESSION_COOKIE = 'railops_session';
11	const IS_SECURE = process.env.SECURITY_MODE !== 'test' && process.env.NODE_ENV !== 'test';
12	
13	function setSessionCookie(ctx, token) {
14	  ctx.cookies.set(SESSION_COOKIE, token, {
15	    httpOnly: true,
16	    secure: IS_SECURE,
17	    sameSite: 'strict',
18	    maxAge: 30 * 24 * 60 * 60 * 1000, // 30 days
19	    path: '/'
20	  });
21	}
22	
23	function clearSessionCookie(ctx) {
24	  ctx.cookies.set(SESSION_COOKIE, '', { maxAge: 0, path: '/' });
25	}
26	
27	// POST /api/auth/login
28	const LOGIN_RATE_LIMIT = parseInt(process.env.LOGIN_RATE_LIMIT, 10) || 10;
29	router.post('/login', rateLimiter({ windowMs: 10 * 60 * 1000, max: LOGIN_RATE_LIMIT }), async (ctx) => {
30	  const { username, password, deviceFingerprint } = ctx.request.body || {};
31	
32	  if (!username || !password) {
33	    ctx.status = 400;
34	    ctx.body = { success: false, error: { code: 'VALIDATION_ERROR', message: 'Username and password are required.' } };
35	    return;
36	  }
37	
38	  if (!deviceFingerprint || typeof deviceFingerprint !== 'string' || deviceFingerprint.trim().length === 0) {
39	    ctx.status = 400;
40	    ctx.body = { success: false, error: { code: 'VALIDATION_ERROR', message: 'Device fingerprint is required.' } };
41	    return;
42	  }
43	
44	  const result = await authService.login({ username, password, deviceFingerprint, ipAddress: ctx.ip });
45	
46	  // Map authService result to correct HTTP status codes
47	  if (result.locked) {
48	    ctx.status = 423;
49	    ctx.body = { success: false, error: { code: 'ACCOUNT_LOCKED', message: result.error } };
50	    return;
51	  }
52	
53	  if (result.enrollmentRequired) {
54	    ctx.status = 401;
55	    ctx.body = { success: false, error: { code: 'ENROLLMENT_REQUIRED', message: result.error, enrollmentRequired: true } };
56	    return;
57	  }
58	
59	  if (result.requireDeviceVerification) {
60	    ctx.status = 403;
61	    ctx.body = {
62	      success: false,
63	      error: {
64	        code: 'DEVICE_VERIFICATION_REQUIRED',
65	        message: 'New device detected. Recovery code required.',
66	        sessionToken: result.sessionToken
67	      }
68	    };
69	    return;
70	  }
71	
72	  if (!result.success) {
73	    ctx.status = 401;
74	    ctx.body = { success: false, error: { code: 'INVALID_CREDENTIALS', message: result.error } };
75	    return;
76	  }
77	
78	  // Success — set cookie + return token
79	  setSessionCookie(ctx, result.token);
80	  ctx.status = 200;
81	  ctx.body = { success: true, data: result };
82	});
83	
84	// POST /api/auth/logout
85	router.post('/logout', authenticate(), async (ctx) => {
86	  await db('sessions').where('id', ctx.state.session.id).del();
87	  clearSessionCookie(ctx);
88	  await logAudit(ctx.state.user.id, ctx.state.user.username, 'logout', 'session', null, null, ctx.ip);
89	  ctx.body = { success: true, data: { message: 'Session invalidated.' } };
90	});
