92	// POST /api/auth/verify-device
93	router.post('/verify-device', async (ctx) => {
94	  const { code, sessionToken, deviceFingerprint } = ctx.request.body || {};
95	
96	  if (!code || !sessionToken) {
97	    ctx.status = 400;
98	    ctx.body = { success: false, error: { code: 'VALIDATION_ERROR', message: 'Recovery code and session token required.' } };
99	    return;
100	  }
101	
102	  if (!deviceFingerprint || typeof deviceFingerprint !== 'string' || deviceFingerprint.trim().length === 0) {
103	    ctx.status = 400;
104	    ctx.body = { success: false, error: { code: 'VALIDATION_ERROR', message: 'Device fingerprint is required for verification.' } };
105	    return;
106	  }
107	
108	  const crypto = require('crypto');
109	  const sessionTokenHash = crypto.createHash('sha256').update(sessionToken).digest('hex');
110	  const pendingSession = await db('sessions')
111	    .where('id', sessionTokenHash)
112	    .where('state', 'pending_verification')
113	    .where('device_fingerprint', 'PENDING_VERIFICATION')
114	    .where('expires_at', '>', new Date())
115	    .first();
116	
117	  if (!pendingSession) {
118	    ctx.status = 401;
119	    ctx.body = { success: false, error: { code: 'VERIFICATION_FAILED', message: 'Invalid or expired verification session.' } };
120	    return;
121	  }
122	
123	  const userId = pendingSession.user_id;
124	  const result = await authService.verifyDevice(userId, code, deviceFingerprint);
125	
126	  if (!result.success) {
127	    ctx.status = 401;
128	    ctx.body = { success: false, error: { code: 'VERIFICATION_FAILED', message: 'Invalid recovery code.' } };
129	    return;
130	  }
131	
132	  // Clean up pending session
133	  await db('sessions').where('id', sessionTokenHash).del();
134	
135	  // Set cookie for the new session
136	  setSessionCookie(ctx, result.token);
137	  ctx.body = { success: true, data: result };
138	});
