158	router.post('/recovery-codes', authenticate(), async (ctx) => {
159	  const codes = await authService.generateRecoveryCodes(ctx.state.user.id);
160	  await logAudit(ctx.state.user.id, ctx.state.user.username, 'recovery_codes_generated', 'recovery_codes', null, { count: codes.length }, ctx.ip);
161	  ctx.body = {
162	    success: true,
163	    data: { codes, warning: 'Store these codes securely. They will not be shown again.' }
164	  };
165	});
