7	const BCRYPT_COST = 12;
8	const MAX_FAILED_ATTEMPTS = 5;
9	const LOCKOUT_WINDOW_MS = 10 * 60 * 1000;
10	const LOCKOUT_DURATION_MS = 15 * 60 * 1000;
11	const MAX_LOCKOUTS_24H = 3;
