203	async function verifyDevice(userId, code, deviceFingerprint) {
204	  const codes = await db('recovery_codes').where('user_id', userId).where('is_used', false);
205	
206	  for (const stored of codes) {
207	    const match = await bcrypt.compare(code, stored.code_hash);
208	    if (match) {
209	      await db('recovery_codes').where('id', stored.id).update({ is_used: true, used_at: new Date() });
210	
211	      const user = await db('users').where('id', userId).first();
212	
213	      // Require fingerprint
214	      if (!deviceFingerprint || typeof deviceFingerprint !== 'string' || deviceFingerprint.trim().length === 0) {
215	        return { success: false, error: 'Device fingerprint is required for verification.' };
216	      }
217	
218	      // Trust the device
219	      await db('trusted_devices').insert({ user_id: userId, device_fingerprint: deviceFingerprint }).catch(() => {});
220	
221	      // Enforce session cap — only count active sessions, not pending_verification
222	      const activeCount = await db('sessions')
223	        .where('user_id', userId)
224	        .where('state', 'active')
225	        .where('expires_at', '>', new Date())
226	        .count('id as count')
227	        .first();
228	
229	      let maxSessions = user.max_sessions || 2;
230	      const exception = await db('session_exceptions')
231	        .where('user_id', userId)
232	        .where(function() { this.whereNull('expires_at').orWhere('expires_at', '>', new Date()); })
233	        .orderBy('created_at', 'desc')
234	        .first();
235	      if (exception) maxSessions = exception.max_sessions;
236	
237	      if (activeCount.count >= maxSessions) {
238	        const oldest = await db('sessions')
239	          .where('user_id', userId)
240	          .orderBy('last_active_at', 'asc')
241	          .first();
242	        if (oldest) await db('sessions').where('id', oldest.id).del();
243	      }
244	
245	      const token = uuidv4();
246	      const tokenHash = crypto.createHash('sha256').update(token).digest('hex');
247	      const expiresAt = new Date(Date.now() + SESSION_HARD_EXPIRY_DAYS * 24 * 60 * 60 * 1000);
248	      await db('sessions').insert({ id: tokenHash, user_id: userId, device_fingerprint: deviceFingerprint, state: 'active', expires_at: expiresAt });
249	
250	      await logAudit(userId, user.username, 'device_verified', 'trusted_device', null, { deviceFingerprint });
251	
252	      return {
253	        success: true,
254	        token,
255	        user: { id: user.id, username: user.username, display_name: user.display_name, role: user.role, phone_last4: user.phone_last4 }
256	      };
257	    }
258	  }
259	
260	  return { success: false, error: 'Invalid recovery code.' };
261	}
