263	async function generateRecoveryCodes(userId) {
264	  await db('recovery_codes').where('user_id', userId).del();
265	
266	  const codes = [];
267	  for (let i = 0; i < 10; i++) {
268	    const code = crypto.randomBytes(4).toString('hex').toUpperCase();
269	    const hash = await bcrypt.hash(code, BCRYPT_COST);
270	    codes.push({ plaintext: code, hash });
271	  }
272	
273	  await db('recovery_codes').insert(codes.map(c => ({ user_id: userId, code_hash: c.hash })));
274	  return codes.map(c => c.plaintext);
275	}
