34	    'users.max_sessions',
35	    'users.created_at',
36	    'users.updated_at'
37	  );
38	
39	  let countQuery = db('users');
40	
41	  if (role) {
42	    query = query.where('users.role', role);
43	    countQuery = countQuery.where('users.role', role);
44	  }
45	
46	  if (q) {
47	    const search = `%${q}%`;
48	    query = query.where(function () {
49	      this.where('users.username', 'like', search)
50	        .orWhere('users.display_name', 'like', search);
51	    });
52	    countQuery = countQuery.where(function () {
53	      this.where('users.username', 'like', search)
54	        .orWhere('users.display_name', 'like', search);
55	    });
56	  }
57	
58	  const totalResult = await countQuery.count('users.id as count').first();
59	  const total = totalResult ? totalResult.count : 0;
60	
61	  const users = await query.orderBy('users.created_at', 'desc').limit(limit).offset(offset);
62	
63	  // Batch-fetch active session counts for listed users
64	  const userIds = users.map((u) => u.id);
