84	      .select('username')
85	      .whereIn('username', users.map(u => u.username))
86	      .whereNull('unlocked_at');
87	    const lockedUsernames = new Set(lockRows.map(r => r.username));
88	    for (const u of users) {
89	      if (lockedUsernames.has(u.username)) lockedUserIds.add(u.id);
90	    }
91	  }
92	
